import { useEffect, useState } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { motion } from 'framer-motion'
import { useAuthStore } from '@/store/useAuthStore'
import { loadVerbs, recordVerbAttempt, TENSES, TENSE_LABEL, PERSONS, PERSON_LABEL, PERSON_DE, hasUsableTense, type Tense, type Person, type VerbRow } from '@/lib/verbs'
import { awardXp } from '@/lib/xp'
import { Header } from '@/components/Header'
import { XPToast, type XpToastData } from '@/components/XPToast'
import { ScoreScreen } from '@/components/ScoreScreen'

// 7c — Reverse-Erkennung: konjugierte Form anzeigen, User wählt Person + Tempus.
//   +15 XP wenn beides korrekt, 0 sonst (CLAUDE.md §6.7)
//   Wir nutzen den url-tense param als Default-Filter, aber zeigen GEMISCHT
//   alle Tempora als Auswahl (das ist die Pointe — der User soll erkennen).

const ROUND_SIZE = 8

type Question = { verb: VerbRow; tense: Tense; person: Person; form: string }

export default function Reverse() {
  const { user } = useAuthStore()
  const navigate = useNavigate()
  const [params] = useSearchParams()
  const filterTense = (params.get('tense') ?? 'present_indefinite') as Tense

  const [verbs, setVerbs] = useState<VerbRow[] | null>(null)
  const [round, setRound] = useState<Question[]>([])
  const [step, setStep] = useState(0)
  const [pickedPerson, setPickedPerson] = useState<Person | null>(null)
  const [pickedTense, setPickedTense] = useState<Tense | null>(null)
  const [verdict, setVerdict] = useState<'pending' | 'right' | 'wrong'>('pending')
  const [stats, setStats] = useState({ correct: 0, wrong: 0, totalXp: 0, mastered: [] as string[] })
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false
    async function load() {
      try {
        const v = await loadVerbs()
        if (cancelled) return
        const usable = v.filter((x) => hasUsableTense(x, filterTense))
        if (usable.length === 0) { setError('Keine Verben.'); return }
        setVerbs(usable)
        startRound(usable)
      } catch (e) { setError(String((e as Error).message ?? e)) }
    }
    void load()
    return () => { cancelled = true }
  }, [filterTense])

  function startRound(pool: VerbRow[]) {
    const qs: Question[] = []
    while (qs.length < ROUND_SIZE) {
      const v = pool[Math.floor(Math.random() * pool.length)]
      const t = filterTense
      const p = PERSONS[Math.floor(Math.random() * PERSONS.length)]
      const form = v.conjugations?.[t]?.[p]
      if (!form) continue
      qs.push({ verb: v, tense: t, person: p, form })
    }
    setRound(qs); setStep(0); setPickedPerson(null); setPickedTense(null); setVerdict('pending'); setStats({ correct: 0, wrong: 0, totalXp: 0, mastered: [] }); setDone(false)
  }

  function handleSubmit() {
    if (!pickedPerson || !pickedTense || !user || verdict !== 'pending') return
    const q = round[step]
    const isCorrect = pickedPerson === q.person && pickedTense === q.tense
    const xp = isCorrect ? 15 : 0
    setVerdict(isCorrect ? 'right' : 'wrong')
    if (xp > 0) {
      void awardXp({ baseAmount: xp, source: 'verb_reverse', mode: 'medical' })
        .then((r) => r && setToast({ id: Date.now(), ...r }))
    }
    void recordVerbAttempt(user.id, q.verb.id, q.tense, isCorrect).then((r) => {
      if (r.justMastered) {
        setStats((s) => ({ ...s, mastered: [...s.mastered, `${q.verb.infinitive} (${TENSE_LABEL[q.tense]})`] }))
        void awardXp({ baseAmount: 75, source: 'verb_mastered', mode: 'medical' })
      }
    })
    setStats((s) => ({ ...s, correct: s.correct + (isCorrect ? 1 : 0), wrong: s.wrong + (isCorrect ? 0 : 1), totalXp: s.totalXp + xp }))
  }

  function handleNext() {
    if (step + 1 >= round.length) { setDone(true); return }
    setStep(step + 1); setPickedPerson(null); setPickedTense(null); setVerdict('pending')
  }

  useEffect(() => { if (toast) { const t = setTimeout(() => setToast(null), 1200); return () => clearTimeout(t) } }, [toast])

  if (error) return <Wrap><Status>⚠ {error}</Status><Back nav={navigate} /></Wrap>
  if (!verbs || round.length === 0) return <Wrap><Status>Wird geladen…</Status></Wrap>
  if (done) {
    return (
      <ScoreScreen
        emoji={stats.correct >= 6 ? '🎉' : '🔍'}
        title={`${stats.correct} / ${ROUND_SIZE} richtig erkannt`}
        subtitle={stats.mastered.length > 0 ? `Neu gemeistert: ${stats.mastered.join(', ')}` : undefined}
        stats={[{ label: 'Richtig (×15)', value: stats.correct, highlight: true }, { label: 'Falsch', value: stats.wrong }]}
        totalXp={stats.totalXp + stats.mastered.length * 75}
        primaryAction={{ label: 'Nochmal', onClick: () => verbs && startRound(verbs) }}
        secondaryAction={{ label: 'Zurück', onClick: () => navigate('/learn/medical/verb-trainer') }}
      />
    )
  }

  const q = round[step]

  return (
    <Wrap>
      <div style={{ width: '100%', maxWidth: 480, fontSize: '0.85rem', opacity: 0.65, marginBottom: '0.4rem' }}>
        {step + 1} / {round.length} · Welche Form ist das?
      </div>
      <div style={{ width: '100%', maxWidth: 480, background: 'var(--white)', border: '2px solid var(--red)', borderRadius: 14, padding: '1.8rem 1rem', textAlign: 'center', boxShadow: 'var(--shadow-card)' }}>
        <div className="hu-vocab" style={{ color: 'var(--red)', fontSize: '2.2rem' }}>{q.form}</div>
        <div style={{ fontSize: '0.85rem', opacity: 0.6, marginTop: 4 }}>von <i>{q.verb.infinitive}</i> · {q.verb.infinitive_de}</div>
      </div>

      <div style={{ width: '100%', maxWidth: 480, marginTop: '1rem' }}>
        <div style={{ fontSize: '0.78rem', opacity: 0.7, marginBottom: 4, fontWeight: 600 }}>Person</div>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
          {PERSONS.map((p) => (
            <Pill key={p} active={pickedPerson === p} disabled={verdict !== 'pending'} onClick={() => setPickedPerson(p)}>
              {PERSON_LABEL[p]}<br /><span style={{ fontSize: '0.65rem', opacity: 0.7 }}>{PERSON_DE[p]}</span>
            </Pill>
          ))}
        </div>
        <div style={{ fontSize: '0.78rem', opacity: 0.7, marginTop: '0.7rem', marginBottom: 4, fontWeight: 600 }}>Tempus</div>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
          {TENSES.map((t) => (
            <Pill key={t} active={pickedTense === t} disabled={verdict !== 'pending'} onClick={() => setPickedTense(t)}>
              {TENSE_LABEL[t]}
            </Pill>
          ))}
        </div>
      </div>

      {verdict === 'pending' ? (
        <button
          onClick={handleSubmit}
          disabled={!pickedPerson || !pickedTense}
          style={{ marginTop: '1rem', background: 'var(--red)', color: 'var(--cream)', border: 'none', padding: '0.7rem 1.5rem', borderRadius: 10, fontWeight: 700, fontSize: '0.95rem', fontFamily: 'inherit', cursor: !pickedPerson || !pickedTense ? 'default' : 'pointer', opacity: !pickedPerson || !pickedTense ? 0.5 : 1 }}
        >
          Prüfen
        </button>
      ) : (
        <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} style={{ marginTop: '1rem', padding: '0.85rem', borderRadius: 12, border: `2px solid ${verdict === 'right' ? 'var(--green)' : 'var(--red)'}`, background: 'var(--white)', textAlign: 'center', maxWidth: 480, width: '100%' }}>
          <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, color: verdict === 'right' ? 'var(--green)' : 'var(--red)' }}>
            {verdict === 'right' ? '✅ Richtig erkannt!' : `❌ Falsch — ${PERSON_LABEL[q.person]} · ${TENSE_LABEL[q.tense]}`}
          </div>
          <button onClick={handleNext} autoFocus style={{ marginTop: '0.7rem', background: verdict === 'right' ? 'var(--green)' : 'var(--red)', color: 'var(--cream)', border: 'none', padding: '0.55rem 1.3rem', borderRadius: 8, fontWeight: 700, fontFamily: 'inherit', cursor: 'pointer' }}>
            {step + 1 >= round.length ? 'Ergebnis' : 'Weiter'}
          </button>
        </motion.div>
      )}

      <Back nav={navigate} />
      <XPToast toast={toast} />
    </Wrap>
  )
}

function Pill({ active, disabled, onClick, children }: { active: boolean; disabled: boolean; onClick: () => void; children: React.ReactNode }) {
  return (
    <button disabled={disabled} onClick={onClick} style={{ padding: '0.45rem 0.7rem', borderRadius: 999, border: '1.5px solid var(--green)', background: active ? 'var(--green)' : 'transparent', color: active ? 'var(--cream)' : 'var(--green)', fontFamily: 'inherit', fontWeight: 600, fontSize: '0.78rem', cursor: disabled ? 'default' : 'pointer', opacity: disabled && !active ? 0.5 : 1, lineHeight: 1.1 }}>
      {children}
    </button>
  )
}

function Wrap({ children }: { children: React.ReactNode }) { return (<div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}><Header /><main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '1.5rem 1rem 3rem' }}>{children}</main></div>) }
function Status({ children }: { children: React.ReactNode }) { return <div style={{ opacity: 0.55, marginTop: '20vh' }}>{children}</div> }
function Back({ nav }: { nav: ReturnType<typeof useNavigate> }) { return <button onClick={() => nav('/learn/medical/verb-trainer')} style={{ marginTop: '1.5rem', background: 'none', border: '1.5px solid rgba(0,0,0,0.15)', padding: '0.45rem 0.9rem', borderRadius: 8, fontFamily: 'inherit', fontSize: '0.8rem', cursor: 'pointer', opacity: 0.65 }}>Sitzung abbrechen</button> }
